#include<iostream>#include<vector>#include<algorithm> using namespace std; bool solve(vector<int>& arr , int k){    int n = arr.size();     if(k == 1){         vector<int>ori = arr;        sort(ori.begin() , ori.end());         for(int i = 0 ; i < n ; i++){            if(arr[i] != ori[i]) return false;        }    }    return true;} int main(){    int t;     cin >> t;     while(t--){        int n , k;         cin >> n >> k;         vector<int>arr(n);         for(int i = 0 ; i < n ; i++){            cin >> arr[i];        }         if(solve(arr , k)) cout << "YES" << "\n";        else cout << "NO" << "\n";    }    return 0;}